// ── Helpers ───────────────────────────────────────────────────────────────
function formatDate(dateStr) {
  const d = new Date(dateStr + "T12:00:00");
  return d.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" });
}

function uid() {
  return Math.random().toString(36).slice(2, 10);
}

function relTime(d) {
  const s = (Date.now() - new Date(d)) / 1000;
  if (s < 60) return "just now";
  if (s < 3600) return ~~(s / 60) + "m ago";
  if (s < 86400) return ~~(s / 3600) + "h ago";
  return ~~(s / 86400) + "d ago";
}

function scoreLabel(type) {
  if (type === "time") return "Time (mm:ss)";
  if (type === "weight") return "Weight (lbs/kg)";
  if (type === "roundsreps") return "Rounds + Reps (e.g. 18+5)";
  if (type === "reps") return "Reps";
  if (type === "calories") return "Calories";
  if (type === "meters") return "Meters";
  if (type === "text") return "Score / Notes";
  if (type === "noscore") return "Notes (no score)";
  return "Score";
}

function scorePlaceholder(type) {
  if (type === "time") return "4:32";
  if (type === "weight") return "185";
  if (type === "roundsreps") return "18+5";
  if (type === "reps") return "42";
  if (type === "calories") return "120";
  if (type === "meters") return "500";
  if (type === "text") return "Completed / PR notes...";
  return "";
}

function getRank(scores, scoreType) {
  return [...scores].sort((a, b) => {
    if (scoreType === "time") {
      const toSec = (v) => {
        const parts = v.split(":").map(Number);
        return parts.length === 2 ? parts[0] * 60 + parts[1] : Number(v);
      };
      return toSec(a.value) - toSec(b.value);
    }
    if (scoreType === "text" || scoreType === "noscore") return 0;
    if (scoreType === "roundsreps") {
      const toNum = (v) => {
        const parts = v.toString().split("+").map(Number);
        return (parts[0] || 0) * 1000 + (parts[1] || 0);
      };
      return toNum(b.value) - toNum(a.value);
    }
    const aNum = parseFloat(a.value.toString().replace("+", ".")) || 0;
    const bNum = parseFloat(b.value.toString().replace("+", ".")) || 0;
    return bNum - aNum;
  });
}

