// ── Components ─────────────────────────────────────────────────────────────

function StyleTag() {
  return <style dangerouslySetInnerHTML={{ __html: globalCSS }} />;
}

function Nav({ user, onLogout, notifications, onOpenNotifs, showNotifs, onCloseNotifs }) {
  const myNotifs = notifications.filter(n => n.userId === user.id);
  const unread = myNotifs.filter(n => !n.read).length;
  return (
    <nav className="nav">
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <img src={GORILLA_IMG} alt="TTD" style={{ width: 32, height: 32, objectFit: "contain", filter: "invert(1) brightness(0.85)" }} />
        <div className="nav-logo">TTD <span>ARENA</span></div>
      </div>
      <div className="nav-right">
        <span className="nav-user">{user.name}</span>
        <span className={`nav-badge ${user.role}`}>{user.role}</span>
        <div className="notif-wrap">
          <button className="btn-logout" style={{ position: "relative" }} onClick={onOpenNotifs}>
            🔔{unread > 0 && <span className="notif-dot" />}
          </button>
          {showNotifs && (
            <div className="notif-panel">
              <div className="notif-header">Notifications</div>
              {myNotifs.length === 0
                ? <div style={{ padding: 16, fontSize: 13, color: "var(--sub)" }}>No notifications</div>
                : [...myNotifs].reverse().map(n => (
                  <div key={n.id} className={`notif-item ${n.read ? "" : "unread"}`}>
                    <div className="notif-text">{n.text}</div>
                    <div className="notif-time">{relTime(n.date)}</div>
                  </div>
                ))
              }
            </div>
          )}
        </div>
        <button className="btn-logout" onClick={onLogout}>Sign Out</button>
      </div>
    </nav>
  );
}

// ── LOGIN ──────────────────────────────────────────────────────────────────
function LoginScreen({ onLogin, users, setUsers }) {
  const [tab, setTab] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [coachPin, setCoachPin] = useState("");
  const [isCoach, setIsCoach] = useState(false);
  const [error, setError] = useState("");
  // register fields
  const [rName, setRName] = useState("");
  const [rEmail, setREmail] = useState("");
  const [rPass, setRPass] = useState("");
  const [rPass2, setRPass2] = useState("");

  function handleLogin() {
    if (isCoach) {
      const coach = users.find(u => u.role === "coach" && u.pin === coachPin);
      if (!coach) { setError("Invalid coach PIN."); return; }
      onLogin(coach);
    } else {
      const found = users.find(u => u.email && u.email.toLowerCase() === email.trim().toLowerCase() && u.password === password);
      if (!found) { setError("Invalid email or password."); return; }
      onLogin(found);
    }
  }

  function handleRegister() {
    if (!rName.trim() || !rEmail.trim() || !rPass) { setError("All fields required"); return; }
    if (rPass !== rPass2) { setError("Passwords don't match"); return; }
    if (users.find(u => u.email && u.email.toLowerCase() === rEmail.trim().toLowerCase())) { setError("Email already in use"); return; }
    const nu = { id: "u" + Date.now(), name: rName.trim(), email: rEmail.trim(), password: rPass, role: "athlete", avatar: null, bio: "" };
    setUsers(p => [...p, nu]);
    onLogin(nu);
  }

  return (
    <div className="login-wrap">
      <div className="login-bg" />
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginBottom: 0 }}>
        <img src={GORILLA_IMG} alt="TTD" style={{ width: 130, height: 130, objectFit: "contain", marginBottom: -8, filter: "invert(1) brightness(0.9)" }} />
        <div className="login-logo">TTD <span>ARENA</span></div>
      </div>
      <div className="login-sub">Train · Track · Dominate</div>
      <div className="login-card">
        {error && <div className="error-msg">{error}</div>}

        {tab === "login" ? (
          <>
            <div style={{ display: "flex", gap: 0, marginBottom: 16, border: "1px solid var(--border)", borderRadius: 2, overflow: "hidden" }}>
              <button className={`login-tab ${!isCoach ? "active" : ""}`} style={{ flex: 1 }} onClick={() => { setIsCoach(false); setError(""); }}>Athlete</button>
              <button className={`login-tab ${isCoach ? "active" : ""}`} style={{ flex: 1 }} onClick={() => { setIsCoach(true); setError(""); }}>Coach</button>
            </div>
            {isCoach ? (
              <>
                <label className="field-label">Coach PIN</label>
                <input className="field-input" type="password" maxLength={4} placeholder="••••" value={coachPin} onChange={e => { setCoachPin(e.target.value); setError(""); }} onKeyDown={e => e.key === "Enter" && handleLogin()} />
                <div style={{ marginBottom: 16, fontSize: 11, color: "var(--sub)" }}>Demo PIN: 1234</div>
              </>
            ) : (
              <>
                <label className="field-label">Email</label>
                <input className="field-input" type="email" placeholder="you@email.com" value={email} onChange={e => { setEmail(e.target.value); setError(""); }} />
                <label className="field-label">Password</label>
                <input className="field-input" type="password" placeholder="••••••••" value={password} onChange={e => { setPassword(e.target.value); setError(""); }} onKeyDown={e => e.key === "Enter" && handleLogin()} />
                <div style={{ marginBottom: 16, fontSize: 11, color: "var(--sub)" }}>Demo: sarah@ttd.com / pass1234</div>
              </>
            )}
            <button className="btn-primary" onClick={handleLogin}>Enter →</button>
            <div style={{ display: "flex", justifyContent: "center", marginTop: 20, gap: 6, fontSize: 12, color: "var(--sub)" }}>
              <span>Don't have an account?</span>
              <span style={{ color: "var(--orange)", cursor: "pointer", fontWeight: 600 }} onClick={() => { setTab("register"); setError(""); }}>Create Account</span>
            </div>
          </>
        ) : (
          <>
            <label className="field-label">Full Name</label>
            <input className="field-input" placeholder="Your name" value={rName} onChange={e => setRName(e.target.value)} />
            <label className="field-label">Email</label>
            <input className="field-input" type="email" placeholder="you@email.com" value={rEmail} onChange={e => setREmail(e.target.value)} />
            <label className="field-label">Password</label>
            <input className="field-input" type="password" placeholder="••••••••" value={rPass} onChange={e => setRPass(e.target.value)} />
            <label className="field-label">Confirm Password</label>
            <input className="field-input" type="password" placeholder="••••••••" value={rPass2} onChange={e => setRPass2(e.target.value)} onKeyDown={e => e.key === "Enter" && handleRegister()} />
            <button className="btn-primary" onClick={handleRegister}>Create Account →</button>
            <div style={{ display: "flex", justifyContent: "center", marginTop: 20, gap: 6, fontSize: 12, color: "var(--sub)" }}>
              <span>Already have an account?</span>
              <span style={{ color: "var(--orange)", cursor: "pointer", fontWeight: 600 }} onClick={() => { setTab("login"); setError(""); }}>Sign In</span>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ── WORKOUT MODAL (Coach) ──────────────────────────────────────────────────
const WORKOUT_TYPES = ["AMRAP", "For Time", "EMOM", "Interval", "PPM Conditioning", "Strength", "Weightlifting", "Gymnastics"];
const SCORE_TYPES = [
  { value: "time",      label: "Time (fastest wins)" },
  { value: "roundsreps",label: "Rounds and Reps (most wins)" },
  { value: "reps",      label: "Reps (most wins)" },
  { value: "weight",    label: "Weight (heaviest wins)" },
  { value: "calories",  label: "Calories (most wins)" },
  { value: "meters",    label: "Meters (most wins)" },
  { value: "text",      label: "Text / Notes" },
  { value: "noscore",   label: "No Score" },
];

function WorkoutModal({ workout, onSave, onClose }) {
  const [form, setForm] = useState(workout || {
    title: "", type: "For Time", scoreType: "time", rounds: 1, totalScore: false, description: "", notes: "", date: today,
  });

  function set(k, v) { setForm(f => ({ ...f, [k]: v })); }

  function handleSave() {
    if (!form.title.trim() || !form.description.trim()) return;
    const rounds = Math.max(1, parseInt(form.rounds) || 1);
    onSave({ ...form, rounds, id: workout?.id || uid(), createdBy: "coach1" });
    onClose();
  }

  const multiRound = (form.rounds || 1) > 1;
  const hasScore = form.scoreType !== "noscore";

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 520 }}>
        <div className="modal-header">
          <div className="modal-title">{workout ? "EDIT WORKOUT" : "NEW WORKOUT"}</div>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          <div className="form-row">
            <label className="field-label">Date</label>
            <input className="field-input" type="date" value={form.date} onChange={e => set("date", e.target.value)} />
          </div>
          <div className="form-grid form-row">
            <div>
              <label className="field-label">Workout Name</label>
              <input className="field-input" placeholder="FRAN, HELEN…" value={form.title} onChange={e => set("title", e.target.value.toUpperCase())} />
            </div>
            <div>
              <label className="field-label">Workout Type</label>
              <select className="field-select" value={form.type} onChange={e => set("type", e.target.value)}>
                {WORKOUT_TYPES.map(t => <option key={t}>{t}</option>)}
              </select>
            </div>
          </div>

          <div className="form-row">
            <label className="field-label">Score Type</label>
            <select className="field-select" value={form.scoreType} onChange={e => set("scoreType", e.target.value)}>
              {SCORE_TYPES.map(s => <option key={s.value} value={s.value}>{s.label}</option>)}
            </select>
          </div>

          {hasScore && (
            <div className="form-grid form-row" style={{ alignItems: "flex-end" }}>
              <div>
                <label className="field-label">Number of Rounds</label>
                <input
                  className="field-input"
                  type="number"
                  min={1}
                  max={20}
                  value={form.rounds || 1}
                  onChange={e => set("rounds", e.target.value)}
                  placeholder="1"
                />
                <div style={{ fontSize: 11, color: "var(--sub)", marginTop: 4 }}>Athletes enter one score per round</div>
              </div>
              {multiRound && (
                <div>
                  <label className="field-label">Round Scoring</label>
                  <div style={{ display: "flex", gap: 0, border: "1px solid var(--border)", borderRadius: 2, overflow: "hidden", marginTop: 2 }}>
                    <button
                      style={{ flex: 1, padding: "9px 8px", fontSize: 12, fontFamily: "Inter", fontWeight: 600, border: "none", cursor: "pointer", background: form.totalScore ? "none" : "var(--orange)", color: form.totalScore ? "var(--sub)" : "#fff", transition: "all .15s" }}
                      onClick={() => set("totalScore", false)}
                    >Best Round</button>
                    <button
                      style={{ flex: 1, padding: "9px 8px", fontSize: 12, fontFamily: "Inter", fontWeight: 600, border: "none", cursor: "pointer", background: form.totalScore ? "var(--orange)" : "none", color: form.totalScore ? "#fff" : "var(--sub)", transition: "all .15s" }}
                      onClick={() => set("totalScore", true)}
                    >Total</button>
                  </div>
                  <div style={{ fontSize: 11, color: "var(--sub)", marginTop: 4 }}>{form.totalScore ? "Sum all rounds for leaderboard" : "Best single round counts"}</div>
                </div>
              )}
            </div>
          )}

          <div className="form-row">
            <label className="field-label">Description</label>
            <textarea className="field-textarea" rows={5} placeholder={"21-15-9\nThrusters (95/65 lb)\nPull-ups"} value={form.description} onChange={e => set("description", e.target.value)} />
          </div>
          <div className="form-row">
            <label className="field-label">Coach Notes (optional)</label>
            <input className="field-input" placeholder="Scaling options, tips…" value={form.notes} onChange={e => set("notes", e.target.value)} />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-sm" onClick={onClose}>Cancel</button>
          <button className="btn-primary" style={{ width: "auto", padding: "10px 28px", fontSize: 16 }} onClick={handleSave}>SAVE WORKOUT</button>
        </div>
      </div>
    </div>
  );
}

// ── SCORE MODAL ────────────────────────────────────────────────────────────
function computeDisplayValue(roundValues, scoreType, totalScore) {
  const vals = roundValues.filter(v => v.trim() !== "");
  if (vals.length === 0) return "";
  if (scoreType === "time") {
    if (totalScore) {
      const toSec = v => { const p = v.split(":").map(Number); return p.length === 2 ? p[0]*60+p[1] : Number(v); };
      const total = vals.reduce((s,v) => s + toSec(v), 0);
      return Math.floor(total/60) + ":" + String(total%60).padStart(2,"0");
    }
    const toSec = v => { const p = v.split(":").map(Number); return p.length === 2 ? p[0]*60+p[1] : Number(v); };
    return vals.reduce((best, v) => toSec(v) < toSec(best) ? v : best);
  }
  if (scoreType === "roundsreps") {
    const toNum = v => { const p = v.toString().split("+").map(Number); return (p[0]||0)*1000+(p[1]||0); };
    if (totalScore) {
      const rounds = vals.reduce((s,v) => s + (parseInt(v.split("+")[0])||0), 0);
      const reps = vals.reduce((s,v) => s + (parseInt(v.split("+")[1])||0), 0);
      return reps > 0 ? rounds + "+" + reps : String(rounds);
    }
    return vals.reduce((best,v) => toNum(v) > toNum(best) ? v : best);
  }
  const nums = vals.map(v => parseFloat(v.replace("+","."))||0);
  if (totalScore) return String(nums.reduce((s,n) => s+n, 0));
  return String(Math.max(...nums));
}

function ScoreModal({ workout, existingScore, athleteId, onSave, onClose }) {
  const rounds = Math.max(1, parseInt(workout.rounds) || 1);
  const isNoScore = workout.scoreType === "noscore";

  // Initialize round values from existing score
  const initRoundVals = () => {
    if (existingScore?.roundValues) return existingScore.roundValues;
    if (existingScore?.value && rounds === 1) return [existingScore.value];
    return Array(rounds).fill("");
  };

  const [roundValues, setRoundValues] = useState(initRoundVals);
  const [rx, setRx] = useState(existingScore?.rx ?? true);
  const [notes, setNotes] = useState(existingScore?.notes || "");

  function setRound(i, v) { setRoundValues(rv => { const n = [...rv]; n[i] = v; return n; }); }

  function handleSave() {
    if (!isNoScore && roundValues.every(v => !v.trim())) return;
    const displayVal = isNoScore ? "—" : computeDisplayValue(roundValues, workout.scoreType, workout.totalScore);
    onSave({
      id: existingScore?.id || uid(),
      workoutId: workout.id,
      userId: athleteId,
      value: displayVal,
      roundValues,
      rx,
      notes,
    });
    onClose();
  }

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <div>
            <div className="modal-title">LOG SCORE</div>
            <div style={{ fontSize: 12, color: "var(--sub)", marginTop: 2 }}>{workout.title} · <span style={{ color: "var(--orange)" }}>{workout.type}</span></div>
          </div>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {!isNoScore && (
            <>
              {rounds === 1 ? (
                <div className="form-row">
                  <label className="field-label">{scoreLabel(workout.scoreType)}</label>
                  <input className="field-input" placeholder={scorePlaceholder(workout.scoreType)} value={roundValues[0] || ""} onChange={e => setRound(0, e.target.value)} autoFocus />
                </div>
              ) : (
                <div className="form-row">
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                    <label className="field-label" style={{ marginBottom: 0 }}>{rounds} Rounds · {scoreLabel(workout.scoreType)}</label>
                    <span style={{ fontSize: 11, color: "var(--sub)", letterSpacing: 1 }}>{workout.totalScore ? "TOTAL" : "BEST ROUND"} counts</span>
                  </div>
                  {Array.from({ length: rounds }, (_, i) => (
                    <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}>
                      <span style={{ fontSize: 12, color: "var(--sub)", fontFamily: "Barlow Condensed", width: 60, flexShrink: 0, letterSpacing: 1 }}>ROUND {i+1}</span>
                      <input
                        className="field-input"
                        style={{ marginBottom: 0 }}
                        placeholder={scorePlaceholder(workout.scoreType)}
                        value={roundValues[i] || ""}
                        onChange={e => setRound(i, e.target.value)}
                        autoFocus={i === 0}
                      />
                    </div>
                  ))}
                  {roundValues.some(v => v.trim()) && (
                    <div style={{ marginTop: 8, padding: "8px 12px", background: "var(--dark)", borderRadius: 2, fontSize: 13, color: "var(--sub)" }}>
                      <span>Leaderboard score: </span>
                      <span style={{ color: "var(--green)", fontFamily: "JetBrains Mono", fontWeight: 600 }}>
                        {computeDisplayValue(roundValues.map(v => v||"0"), workout.scoreType, workout.totalScore) || "—"}
                      </span>
                    </div>
                  )}
                </div>
              )}
            </>
          )}
          <div className="form-row">
            <label className="field-label">Rx / Scaled</label>
            <div className="rx-toggle">
              <button className={`rx-opt ${rx ? "active rx" : ""}`} onClick={() => setRx(true)}>RX</button>
              <button className={`rx-opt ${!rx ? "active sc" : ""}`} onClick={() => setRx(false)}>SCALED</button>
            </div>
          </div>
          <div className="form-row">
            <label className="field-label">Notes (optional)</label>
            <input className="field-input" placeholder="How'd it feel?" value={notes} onChange={e => setNotes(e.target.value)} />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-sm" onClick={onClose}>Cancel</button>
          <button className="btn-score" style={{ fontFamily: "Barlow Condensed", fontSize: 16, padding: "10px 28px" }} onClick={handleSave}>SUBMIT SCORE</button>
        </div>
      </div>
    </div>
  );
}

// ── WORKOUT CARD ───────────────────────────────────────────────────────────
function WorkoutCard({ workout, scores, currentUser, allUsers, onLogScore, onEdit, onDelete, comments, setComments, setNotifications, onViewProfile }) {
  const [showLB, setShowLB] = useState(false);
  const [openCmts, setOpenCmts] = useState({});
  const [cmtInputs, setCmtInputs] = useState({});
  const myScore = scores.find(s => s.userId === currentUser.id);
  const ranked = getRank(scores, workout.scoreType);

  function getUser(id) { return allUsers.find(u => u.id === id); }
  function ini(name) { return (name || "?").split(" ").map(n => n[0]).join(""); }

  function postComment(scoreId, ownerId) {
    const txt = (cmtInputs[scoreId] || "").trim();
    if (!txt) return;
    setComments(p => [...p, { id: uid(), scoreId, authorId: currentUser.id, text: txt, date: new Date().toISOString() }]);
    setCmtInputs(p => ({ ...p, [scoreId]: "" }));
    if (ownerId !== currentUser.id) {
      setNotifications(p => [...p, { id: uid(), userId: ownerId, text: currentUser.name + " commented on your score", read: false, date: new Date().toISOString() }]);
    }
  }

  return (
    <div className="workout-card">
      <div className="wod-header">
        <div className="wod-title-wrap">
          <div className="wod-title">{workout.title}</div>
          <span className="wod-type-badge">{workout.type}</span>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {currentUser.role === "coach" && (
            <>
              <button className="btn-sm" onClick={() => onEdit(workout)}>Edit</button>
              <button className="btn-danger" onClick={() => onDelete(workout.id)}>Delete</button>
            </>
          )}
        </div>
      </div>
      <div className="wod-body">
        <div className="wod-desc">{workout.description}</div>
        {workout.notes && <div className="wod-notes">📋 {workout.notes}</div>}
      </div>
      <div className="wod-footer">
        <div className="score-count">
          <b>{scores.length}</b> {scores.length === 1 ? "score" : "scores"} logged
          {myScore && workout.scoreType !== "noscore" && <span style={{ marginLeft: 12, color: "var(--green)" }}>✓ Your score: <b style={{ fontFamily: "JetBrains Mono" }}>{myScore.value}</b></span>}
          {myScore && workout.scoreType === "noscore" && <span style={{ marginLeft: 12, color: "var(--green)" }}>✓ Logged</span>}
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <button className="btn-sm" onClick={() => setShowLB(v => !v)}>
            {showLB ? "Hide Scores" : "View Scores" + (scores.length > 0 ? ` (${scores.length})` : "")}
          </button>
          {currentUser.role === "athlete" && (
            <button className="btn-score" onClick={() => onLogScore(workout, myScore)}>
              {myScore ? "UPDATE SCORE" : "LOG SCORE"}
            </button>
          )}
        </div>
      </div>

      {showLB && (
        <div style={{ padding: "0 20px 16px" }}>
          <div className="leaderboard">
            {ranked.length === 0 ? (
              <div style={{ fontSize: 13, color: "var(--sub)", padding: "8px 0" }}>No scores yet. Be first!</div>
            ) : (
              ranked.map((s, i) => {
                const athlete = getUser(s.userId);
                const isMe = s.userId === currentUser.id;
                const rankClass = i === 0 ? "gold" : i === 1 ? "silver" : i === 2 ? "bronze" : "";
                const scoreCmts = comments.filter(c => c.scoreId === s.id);
                const cmtOpen = openCmts[s.id];
                return (
                  <div key={s.id}>
                    <div className={`lb-row${isMe ? " lb-me" : ""}`}>
                      <div className={`lb-rank ${rankClass}`}>{i + 1}</div>
                      <div style={{ width: 30, height: 30, borderRadius: "50%", background: "var(--orange-dim)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontFamily: "Barlow Condensed", color: "var(--orange)", flexShrink: 0, overflow: "hidden", cursor: "pointer" }}
                        onClick={() => onViewProfile(s.userId)}>
                        {athlete?.avatar ? <img src={athlete.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(athlete?.name || "?")}
                      </div>
                      <div className="lb-name" style={{ cursor: "pointer" }} onClick={() => onViewProfile(s.userId)}>{athlete?.name || "?"}{isMe ? " (you)" : ""}</div>
                      <div className="lb-score">{workout.scoreType !== "noscore" ? s.value : <span style={{color:"var(--sub)",fontSize:12}}>✓</span>}</div>
                      {(workout.rounds||1) > 1 && workout.scoreType !== "noscore" && <span style={{fontSize:10,color:"var(--sub)",letterSpacing:1}}>{workout.totalScore?"TOT":"BEST"}</span>}
                      <span className={`lb-rx ${s.rx ? "rx" : "sc"}`}>{s.rx ? "RX" : "SC"}</span>
                      <button className="btn-sm" style={{ fontSize: 11, padding: "3px 8px" }} onClick={() => setOpenCmts(p => ({ ...p, [s.id]: !p[s.id] }))}>
                        💬 {scoreCmts.length > 0 ? scoreCmts.length : ""}
                      </button>
                      {isMe && currentUser.role !== "coach" && (
                        <button className="btn-sm" style={{ fontSize: 11, padding: "3px 8px" }} onClick={() => onLogScore(workout, s)}>Edit</button>
                      )}
                    </div>
                    {cmtOpen && (
                      <div className="comments-section" style={{ paddingLeft: 40 }}>
                        {scoreCmts.length === 0 && <div style={{ fontSize: 12, color: "var(--sub)", marginBottom: 8 }}>No comments yet.</div>}
                        {scoreCmts.map(c => {
                          const author = getUser(c.authorId);
                          return (
                            <div key={c.id} className="comment-item">
                              <div className="comment-av">
                                {author?.avatar ? <img src={author.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(author?.name || "?")}
                              </div>
                              <div>
                                <div className="comment-author">{author?.name}</div>
                                <div className="comment-text">{c.text}</div>
                                <div className="comment-time">{relTime(c.date)}</div>
                              </div>
                            </div>
                          );
                        })}
                        <div className="comment-input-row">
                          <input className="comment-input" placeholder="Say something..." value={cmtInputs[s.id] || ""} onChange={e => setCmtInputs(p => ({ ...p, [s.id]: e.target.value }))} onKeyDown={e => e.key === "Enter" && postComment(s.id, s.userId)} />
                          <button className="comment-post" onClick={() => postComment(s.id, s.userId)}>Post</button>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ── CHAT VIEW ─────────────────────────────────────────────────────────────
function ChatView({ currentUser, allUsers, messages, setMessages, setNotifications }) {
  const isCoach = currentUser.role === "coach";
  const messagesEndRef = useRef(null);

  // For athlete: only convo with coach. For coach: list of all athletes with convos
  const coachUser = allUsers.find(u => u.role === "coach");
  const athletes = allUsers.filter(u => u.role === "athlete");

  // Selected conversation partner
  const [selectedId, setSelectedId] = useState(() => {
    if (!isCoach) return coachUser?.id || null;
    // Coach: pick first athlete that has messages, else first athlete
    const withMessages = athletes.find(a =>
      messages.some(m => (m.fromId === a.id && m.toId === "coach1") || (m.fromId === "coach1" && m.toId === a.id))
    );
    return withMessages?.id || athletes[0]?.id || null;
  });

  const [input, setInput] = useState("");

  // Get conversation between currentUser and selectedId
  function getConvo(otherId) {
    return messages
      .filter(m =>
        (m.fromId === currentUser.id && m.toId === otherId) ||
        (m.fromId === otherId && m.toId === currentUser.id)
      )
      .sort((a, b) => new Date(a.date) - new Date(b.date));
  }

  function getUnreadCount(otherId) {
    return messages.filter(m => m.fromId === otherId && m.toId === currentUser.id && !m.read).length;
  }

  function getLastMessage(otherId) {
    const convo = getConvo(otherId);
    return convo[convo.length - 1] || null;
  }

  function selectPerson(id) {
    setSelectedId(id);
    // Mark messages from that person as read
    setMessages(ms => ms.map(m =>
      m.fromId === id && m.toId === currentUser.id ? { ...m, read: true } : m
    ));
  }

  function sendMessage() {
    const text = input.trim();
    if (!text || !selectedId) return;
    const msg = {
      id: uid(),
      fromId: currentUser.id,
      toId: selectedId,
      text,
      date: new Date().toISOString(),
      read: false,
    };
    setMessages(ms => [...ms, msg]);
    // Notification for recipient
    setNotifications(ns => [...ns, {
      id: uid(),
      userId: selectedId,
      text: `${currentUser.name}: ${text.length > 40 ? text.slice(0, 40) + "…" : text}`,
      read: false,
      date: new Date().toISOString(),
    }]);
    setInput("");
  }

  // Scroll to bottom when convo changes
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [selectedId, messages.length]);

  // Mark as read on select
  useEffect(() => {
    if (selectedId) {
      setMessages(ms => ms.map(m =>
        m.fromId === selectedId && m.toId === currentUser.id ? { ...m, read: true } : m
      ));
    }
  }, [selectedId]);

  function ini(name) { return (name || "?").split(" ").map(n => n[0]).join(""); }

  function formatMsgTime(dateStr) {
    const d = new Date(dateStr);
    const now = new Date();
    const diffMs = now - d;
    const diffDays = Math.floor(diffMs / 86400000);
    if (diffDays === 0) return d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
    if (diffDays === 1) return "Yesterday " + d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" }) + " " + d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
  }

  function shouldShowDateDivider(msgs, idx) {
    if (idx === 0) return true;
    const prev = new Date(msgs[idx-1].date);
    const curr = new Date(msgs[idx].date);
    return prev.toDateString() !== curr.toDateString();
  }

  function formatDividerDate(dateStr) {
    const d = new Date(dateStr);
    const now = new Date();
    if (d.toDateString() === now.toDateString()) return "Today";
    const yesterday = new Date(now - 86400000);
    if (d.toDateString() === yesterday.toDateString()) return "Yesterday";
    return d.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" });
  }

  const selectedUser = allUsers.find(u => u.id === selectedId);
  const convo = selectedId ? getConvo(selectedId) : [];

  // For athlete view (no sidebar, just chat with coach)
  if (!isCoach) {
    return (
      <div className="chat-layout" style={{ height: "calc(100vh - 112px)" }}>
        <div className="chat-main">
          <div className="chat-header">
            <div style={{ width: 38, height: 38, borderRadius: "50%", background: "var(--orange-dim)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontFamily: "Barlow Condensed", color: "var(--orange)", overflow: "hidden" }}>
              {coachUser?.avatar ? <img src={coachUser.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(coachUser?.name || "Coach")}
            </div>
            <div>
              <div className="chat-header-name">{coachUser?.name || "Coach"}</div>
              <div className="chat-header-role">Head Coach</div>
            </div>
          </div>
          <div className="chat-messages">
            {convo.length === 0 && (
              <div className="chat-empty">
                <div style={{ fontSize: 40 }}>💬</div>
                <div style={{ fontSize: 14, fontWeight: 600 }}>No messages yet</div>
                <div style={{ fontSize: 12 }}>Ask the coach anything about your training!</div>
              </div>
            )}
            {convo.map((msg, i) => {
              const isMine = msg.fromId === currentUser.id;
              const sender = allUsers.find(u => u.id === msg.fromId);
              return (
                <div key={msg.id}>
                  {shouldShowDateDivider(convo, i) && (
                    <div className="chat-date-divider">{formatDividerDate(msg.date)}</div>
                  )}
                  <div className={`chat-bubble-wrap ${isMine ? "mine" : ""}`}>
                    <div className="chat-bubble-av">
                      {sender?.avatar ? <img src={sender.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(sender?.name || "?")}
                    </div>
                    <div>
                      <div className={`chat-bubble ${isMine ? "mine" : "theirs"}`}>{msg.text}</div>
                      <div className="chat-bubble-time">{formatMsgTime(msg.date)}</div>
                    </div>
                  </div>
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>
          <div className="chat-input-area">
            <textarea
              className="chat-input"
              rows={1}
              placeholder="Message coach..."
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
            />
            <button className="chat-send" disabled={!input.trim()} onClick={sendMessage}>↑</button>
          </div>
        </div>
      </div>
    );
  }

  // Coach view: sidebar with athletes + chat panel
  return (
    <div className="chat-layout">
      <div className="chat-sidebar">
        <div className="chat-sidebar-header">MESSAGES</div>
        {athletes.map(a => {
          const last = getLastMessage(a.id);
          const unread = getUnreadCount(a.id);
          return (
            <div key={a.id} className={`chat-person ${selectedId === a.id ? "active" : ""}`} onClick={() => selectPerson(a.id)}>
              <div className="chat-person-av">
                {a.avatar ? <img src={a.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(a.name)}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div className="chat-person-name">{a.name}</div>
                {last && <div className="chat-person-preview">{last.fromId === currentUser.id ? "You: " : ""}{last.text}</div>}
              </div>
              {unread > 0 && <div className="chat-unread-dot" />}
            </div>
          );
        })}
      </div>

      <div className="chat-main">
        {!selectedId ? (
          <div className="chat-empty"><div style={{ fontSize: 40 }}>💬</div><div style={{ fontSize: 14 }}>Select an athlete to message</div></div>
        ) : (
          <>
            <div className="chat-header">
              <div style={{ width: 38, height: 38, borderRadius: "50%", background: "var(--orange-dim)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontFamily: "Barlow Condensed", color: "var(--orange)", overflow: "hidden" }}>
                {selectedUser?.avatar ? <img src={selectedUser.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(selectedUser?.name || "?")}
              </div>
              <div>
                <div className="chat-header-name">{selectedUser?.name}</div>
                <div className="chat-header-role">Athlete</div>
              </div>
            </div>
            <div className="chat-messages">
              {convo.length === 0 && (
                <div className="chat-empty">
                  <div style={{ fontSize: 40 }}>💬</div>
                  <div style={{ fontSize: 14, fontWeight: 600 }}>No messages yet</div>
                  <div style={{ fontSize: 12 }}>Start a conversation with {selectedUser?.name}</div>
                </div>
              )}
              {convo.map((msg, i) => {
                const isMine = msg.fromId === currentUser.id;
                const sender = allUsers.find(u => u.id === msg.fromId);
                return (
                  <div key={msg.id}>
                    {shouldShowDateDivider(convo, i) && (
                      <div className="chat-date-divider">{formatDividerDate(msg.date)}</div>
                    )}
                    <div className={`chat-bubble-wrap ${isMine ? "mine" : ""}`}>
                      <div className="chat-bubble-av">
                        {sender?.avatar ? <img src={sender.avatar} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(sender?.name || "?")}
                      </div>
                      <div>
                        <div className={`chat-bubble ${isMine ? "mine" : "theirs"}`}>{msg.text}</div>
                        <div className="chat-bubble-time">{formatMsgTime(msg.date)}</div>
                      </div>
                    </div>
                  </div>
                );
              })}
              <div ref={messagesEndRef} />
            </div>
            <div className="chat-input-area">
              <textarea
                className="chat-input"
                rows={1}
                placeholder={`Reply to ${selectedUser?.name}...`}
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
              />
              <button className="chat-send" disabled={!input.trim()} onClick={sendMessage}>↑</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ── COACH VIEW ─────────────────────────────────────────────────────────────
function CoachView({ user, workouts, scores, setWorkouts, setScores, allUsers, comments, setComments, notifications, setNotifications, onViewProfile, messages, setMessages }) {
  const [tab, setTab] = useState("workouts");
  const [selectedDate, setSelectedDate] = useState(today);
  const [showModal, setShowModal] = useState(false);
  const [editingWod, setEditingWod] = useState(null);

  // Last 7 days
  const dates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(Date.now() - i * 86400000);
    return d.toISOString().split("T")[0];
  });

  const filtered = workouts.filter(w => w.date === selectedDate);
  const athletes = allUsers.filter(u => u.role === "athlete");
  const totalScores = scores.length;

  function handleSaveWorkout(wod) {
    setWorkouts(ws => {
      const idx = ws.findIndex(w => w.id === wod.id);
      if (idx >= 0) { const n = [...ws]; n[idx] = wod; return n; }
      return [wod, ...ws];
    });
  }

  function handleDeleteWorkout(id) {
    if (!window.confirm("Delete this workout?")) return;
    setWorkouts(ws => ws.filter(w => w.id !== id));
    setScores(ss => ss.filter(s => s.workoutId !== id));
  }

  return (
    <>
      <div className="page-tabs">
        {["workouts", "athletes", "overview", "messages"].map(t => {
          const unread = t === "messages" ? messages.filter(m => m.toId === user.id && !m.read).length : 0;
          return (
            <button key={t} className={`page-tab ${tab === t ? "active" : ""}`} onClick={() => setTab(t)} style={{ position: "relative" }}>
              {t}
              {unread > 0 && <span style={{ position: "absolute", top: 6, right: 4, width: 7, height: 7, borderRadius: "50%", background: "var(--orange)", display: "block" }} />}
            </button>
          );
        })}
      </div>

      {tab === "messages" ? (
        <ChatView
          currentUser={user}
          allUsers={allUsers}
          messages={messages}
          setMessages={setMessages}
          setNotifications={setNotifications}
        />
      ) : (
      <div className="main">
        {tab === "workouts" && (
          <>
            <div className="date-strip">
              {dates.map(d => (
                <button key={d} className={`date-pill ${d === selectedDate ? "active" : ""}`} onClick={() => setSelectedDate(d)}>
                  {d === today ? "Today" : d === dates[1] ? "Yesterday" : formatDate(d)}
                </button>
              ))}
            </div>

            <div className="section-header">
              <div className="section-title">{selectedDate === today ? "TODAY'S WORKOUTS" : formatDate(selectedDate).toUpperCase()}</div>
              <button className="btn-primary" style={{ width: "auto", padding: "10px 20px", fontSize: 15 }} onClick={() => { setEditingWod(null); setShowModal(true); }}>
                + NEW WORKOUT
              </button>
            </div>

            {filtered.length === 0 ? (
              <div className="empty">
                <div className="empty-icon">🏋️</div>
                <div className="empty-text">No workouts for this day. Add one above.</div>
              </div>
            ) : (
              <div className="workout-grid">
                {filtered.map(w => (
                  <WorkoutCard
                    key={w.id}
                    workout={w}
                    scores={scores.filter(s => s.workoutId === w.id)}
                    currentUser={user}
                    allUsers={allUsers}
                    onLogScore={() => {}}
                    onEdit={wod => { setEditingWod(wod); setShowModal(true); }}
                    onDelete={handleDeleteWorkout}
                    comments={comments}
                    setComments={setComments}
                    setNotifications={setNotifications}
                    onViewProfile={onViewProfile}
                  />
                ))}
              </div>
            )}
          </>
        )}

        {tab === "athletes" && (
          <>
            <div className="section-header">
              <div className="section-title">ALL ATHLETES</div>
            </div>
            <div className="athlete-grid" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))" }}>
              {athletes.map(a => {
                const aScores = scores.filter(s => s.userId === a.id);
                return (
                  <div key={a.id} className="athlete-card" style={{ cursor: "default", textAlign: "left" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                      <div className="athlete-avatar" style={{ background: "var(--orange-dim)", color: "var(--orange)" }}>
                        {a.name.split(" ").map(n => n[0]).join("")}
                      </div>
                      <div>
                        <div style={{ fontWeight: 600, fontSize: 14 }}>{a.name}</div>
                        <div style={{ fontSize: 11, color: "var(--sub)" }}>PIN: {a.pin}</div>
                      </div>
                    </div>
                    <div style={{ fontSize: 12, color: "var(--sub)" }}>{aScores.length} scores logged</div>
                  </div>
                );
              })}
            </div>
          </>
        )}

        {tab === "overview" && (
          <>
            <div className="section-title" style={{ marginBottom: 20 }}>GYM OVERVIEW</div>
            <div className="stats-row">
              <div className="stat-card">
                <div className="stat-val">{workouts.length}</div>
                <div className="stat-label">Total Workouts</div>
              </div>
              <div className="stat-card">
                <div className="stat-val">{totalScores}</div>
                <div className="stat-label">Scores Logged</div>
              </div>
              <div className="stat-card">
                <div className="stat-val">{athletes.length}</div>
                <div className="stat-label">Athletes</div>
              </div>
            </div>
            <div className="section-title" style={{ marginBottom: 16 }}>RECENT SCORES</div>
            {scores.slice(-8).reverse().map(s => {
              const w = workouts.find(w => w.id === s.workoutId);
              const a = allUsers.find(u => u.id === s.userId);
              if (!w || !a) return null;
              return (
                <div key={s.id} className="my-score-row">
                  <div style={{ width: 36, height: 36, background: "var(--orange-dim)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, color: "var(--orange)", fontFamily: "Barlow Condensed", flexShrink: 0 }}>
                    {a.name.split(" ").map(n => n[0]).join("")}
                  </div>
                  <div className="my-score-wod">{a.name}</div>
                  <div style={{ fontSize: 12, color: "var(--sub)", flex: 1 }}>{w.title}</div>
                  <div className="my-score-val">{s.value}</div>
                  <span className={`lb-rx ${s.rx ? "rx" : "sc"}`}>{s.rx ? "RX" : "SC"}</span>
                </div>
              );
            })}
          </>
        )}
      </div>
      )}

      {showModal && (
        <WorkoutModal
          workout={editingWod}
          onSave={handleSaveWorkout}
          onClose={() => { setShowModal(false); setEditingWod(null); }}
        />
      )}
    </>
  );
}

// ── ATHLETE VIEW ───────────────────────────────────────────────────────────
function AthleteView({ user, workouts, scores, setScores, allUsers, setAllUsers, comments, setComments, notifications, setNotifications, onViewProfile, messages, setMessages }) {
  const [tab, setTab] = useState("today");
  const unreadMsgs = messages.filter(m => m.toId === user.id && !m.read).length;
  const [selectedDate, setSelectedDate] = useState(today);
  const [scoringWod, setScoringWod] = useState(null);
  const [existingScore, setExistingScore] = useState(null);

  const dates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(Date.now() - i * 86400000);
    return d.toISOString().split("T")[0];
  });

  const filtered = workouts.filter(w => w.date === selectedDate);
  const myScores = scores.filter(s => s.userId === user.id);

  function handleSaveScore(score) {
    setScores(ss => {
      const idx = ss.findIndex(s => s.id === score.id);
      if (idx >= 0) { const n = [...ss]; n[idx] = score; return n; }
      return [...ss, score];
    });
  }

  return (
    <>
      <div className="page-tabs">
        {["today", "my scores", "coach chat", "my profile"].map(t => {
          const badge = t === "coach chat" ? unreadMsgs : 0;
          return (
            <button key={t} className={`page-tab ${tab === t ? "active" : ""}`} onClick={() => setTab(t)} style={{ position: "relative" }}>
              {t}
              {badge > 0 && <span style={{ position: "absolute", top: 6, right: 4, width: 7, height: 7, borderRadius: "50%", background: "var(--orange)", display: "block" }} />}
            </button>
          );
        })}
      </div>

      {tab === "coach chat" ? (
        <ChatView
          currentUser={user}
          allUsers={allUsers}
          messages={messages}
          setMessages={setMessages}
          setNotifications={setNotifications}
        />
      ) : (
      <div className="main">
        {tab === "today" && (
          <>
            <div className="date-strip">
              {dates.map(d => (
                <button key={d} className={`date-pill ${d === selectedDate ? "active" : ""}`} onClick={() => setSelectedDate(d)}>
                  {d === today ? "Today" : d === dates[1] ? "Yesterday" : formatDate(d)}
                </button>
              ))}
            </div>
            <div className="section-header">
              <div className="section-title">{selectedDate === today ? "TODAY'S WORKOUTS" : formatDate(selectedDate).toUpperCase()}</div>
            </div>
            {filtered.length === 0 ? (
              <div className="empty">
                <div className="empty-icon">🏋️</div>
                <div className="empty-text">No workouts programmed for this day.</div>
              </div>
            ) : (
              <div className="workout-grid">
                {filtered.map(w => (
                  <WorkoutCard
                    key={w.id}
                    workout={w}
                    scores={scores.filter(s => s.workoutId === w.id)}
                    currentUser={user}
                    allUsers={allUsers}
                    onLogScore={(wod, existing) => { setScoringWod(wod); setExistingScore(existing || null); }}
                    onEdit={() => {}}
                    onDelete={() => {}}
                    comments={comments}
                    setComments={setComments}
                    setNotifications={setNotifications}
                    onViewProfile={onViewProfile}
                  />
                ))}
              </div>
            )}
          </>
        )}

        {tab === "my scores" && (
          <>
            <div className="section-header">
              <div className="section-title">MY SCORES</div>
              <div style={{ fontSize: 12, color: "var(--sub)" }}>{myScores.length} total</div>
            </div>
            {myScores.length === 0 ? (
              <div className="empty">
                <div className="empty-icon">📊</div>
                <div className="empty-text">You haven't logged any scores yet.</div>
              </div>
            ) : (
              [...myScores].reverse().map(s => {
                const w = workouts.find(wod => wod.id === s.workoutId);
                if (!w) return null;
                return (
                  <div key={s.id} className="my-score-row">
                    <div style={{ flex: 1 }}>
                      <div className="my-score-wod">{w.title}</div>
                      <div style={{ fontSize: 11, color: "var(--sub)" }}>{formatDate(w.date)} · {w.type}</div>
                      {s.notes && <div style={{ fontSize: 11, color: "var(--sub)", marginTop: 3, fontStyle: "italic" }}>{s.notes}</div>}
                    </div>
                    <div className="my-score-val">{s.value}</div>
                    <span className={`lb-rx ${s.rx ? "rx" : "sc"}`}>{s.rx ? "RX" : "SC"}</span>
                    <button className="btn-sm" style={{ fontSize: 11 }} onClick={() => { setScoringWod(w); setExistingScore(s); }}>Edit</button>
                  </div>
                );
              })
            )}
          </>
        )}

        {tab === "my profile" && (
          <ProfilePage
            viewUserId={user.id}
            currentUser={user}
            allUsers={allUsers}
            setAllUsers={setAllUsers}
            scores={scores}
            workouts={workouts}
            onBack={null}
          />
        )}
      </div>
      )}

      {scoringWod && (
        <ScoreModal
          workout={scoringWod}
          existingScore={existingScore}
          athleteId={user.id}
          onSave={handleSaveScore}
          onClose={() => { setScoringWod(null); setExistingScore(null); }}
        />
      )}
    </>
  );
}

// ── PROFILE PAGE ───────────────────────────────────────────────────────────
function ProfilePage({ viewUserId, currentUser, allUsers, setAllUsers, scores, workouts, onBack }) {
  const isOwn = viewUserId === currentUser.id;
  const profileUser = allUsers.find(u => u.id === viewUserId) || currentUser;
  const [editBio, setEditBio] = useState(false);
  const [bioVal, setBioVal] = useState(profileUser.bio || "");
  const fileRef = useRef();
  const userScores = scores.filter(s => s.userId === profileUser.id);

  function onFile(e) {
    const f = e.target.files[0]; if (!f) return;
    const r = new FileReader();
    r.onload = ev => setAllUsers(p => p.map(u => u.id === profileUser.id ? { ...u, avatar: ev.target.result } : u));
    r.readAsDataURL(f);
  }

  function saveBio() {
    setAllUsers(p => p.map(u => u.id === profileUser.id ? { ...u, bio: bioVal } : u));
    setEditBio(false);
  }

  const updated = allUsers.find(u => u.id === profileUser.id) || profileUser;
  function ini(name) { return (name || "?").split(" ").map(n => n[0]).join(""); }

  return (
    <div className="main">
      {onBack && <button className="btn-sm" style={{ marginBottom: 20 }} onClick={onBack}>← Back</button>}
      <div className="profile-hero">
        <div className="profile-av-wrap">
          <div className="profile-av">
            {updated.avatar ? <img src={updated.avatar} alt="" /> : ini(updated.name)}
          </div>
          {isOwn && <div className="profile-av-edit" onClick={() => fileRef.current.click()}>✏️</div>}
          <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={onFile} />
        </div>
        <div className="profile-name">{updated.name}</div>
        <div className="profile-role">{updated.role}</div>
        {editBio ? (
          <div style={{ maxWidth: 340, margin: "8px auto 0" }}>
            <input className="field-input" value={bioVal} onChange={e => setBioVal(e.target.value)} style={{ marginBottom: 8 }} />
            <div style={{ display: "flex", gap: 8, justifyContent: "center" }}>
              <button className="btn-score" style={{ padding: "8px 20px", fontSize: 14 }} onClick={saveBio}>Save</button>
              <button className="btn-sm" onClick={() => setEditBio(false)}>Cancel</button>
            </div>
          </div>
        ) : (
          <>
            <div className="profile-bio">{updated.bio || (isOwn ? "No bio yet." : "")}</div>
            {isOwn && <button className="btn-sm" style={{ marginTop: 8 }} onClick={() => { setEditBio(true); setBioVal(updated.bio || ""); }}>Edit Bio</button>}
          </>
        )}
        <div className="profile-stats">
          <div style={{ textAlign: "center" }}><div className="profile-stat-val">{userScores.length}</div><div className="profile-stat-lbl">Workouts</div></div>
          <div style={{ textAlign: "center" }}><div className="profile-stat-val">{userScores.filter(s => s.rx).length}</div><div className="profile-stat-lbl">RX</div></div>
        </div>
      </div>

      <div className="section-title" style={{ marginBottom: 14 }}>SCORES</div>
      {userScores.length === 0
        ? <div className="empty"><div className="empty-icon">🏋️</div><div className="empty-text">No scores logged yet.</div></div>
        : [...userScores].reverse().map(s => {
          const w = workouts.find(w => w.id === s.workoutId);
          return (
            <div key={s.id} className="my-score-row">
              <div style={{ flex: 1 }}>
                <div className="my-score-wod">{w?.title || "?"}</div>
                <div style={{ fontSize: 11, color: "var(--sub)" }}>{w?.date} · {w?.type}</div>
                {s.notes && <div style={{ fontSize: 11, color: "var(--sub)", fontStyle: "italic", marginTop: 2 }}>{s.notes}</div>}
              </div>
              <div className="my-score-val">{s.value}</div>
              <span className={`lb-rx ${s.rx ? "rx" : "sc"}`}>{s.rx ? "RX" : "SC"}</span>
            </div>
          );
        })
      }
    </div>
  );
}

// ── APP ROOT ───────────────────────────────────────────────────────────────
export default function App() {
  const [allUsers, setAllUsers] = useState(USERS);
  const [user, setUser] = useState(null);
  const [workouts, setWorkouts] = useState(INITIAL_WORKOUTS);
  const [scores, setScores] = useState(INITIAL_SCORES);
  const [comments, setComments] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [messages, setMessages] = useState(INITIAL_MESSAGES);
  const [showNotifs, setShowNotifs] = useState(false);
  const [profileView, setProfileView] = useState(null); // userId
  const notifRef = useRef();

  useEffect(() => {
    const h = e => { if (notifRef.current && !notifRef.current.contains(e.target)) setShowNotifs(false); };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  function openNotifs() {
    setShowNotifs(v => !v);
    setNotifications(p => p.map(n => n.userId === user?.id ? { ...n, read: true } : n));
  }

  function handleLogin(u) {
    // sync in case avatar/bio updated
    const fresh = allUsers.find(x => x.id === u.id) || u;
    setUser(fresh);
  }

  if (!user) return (
    <div className="app">
      <StyleTag />
      <LoginScreen onLogin={handleLogin} users={allUsers} setUsers={setAllUsers} />
    </div>
  );

  if (profileView) return (
    <div className="app">
      <StyleTag />
      <div ref={notifRef} style={{ position: "relative" }}>
        <Nav user={user} onLogout={() => { setUser(null); setProfileView(null); }} notifications={notifications} onOpenNotifs={openNotifs} showNotifs={showNotifs} onCloseNotifs={() => setShowNotifs(false)} />
      </div>
      <ProfilePage
        viewUserId={profileView}
        currentUser={user}
        allUsers={allUsers}
        setAllUsers={setAllUsers}
        scores={scores}
        workouts={workouts}
        onBack={() => setProfileView(null)}
      />
    </div>
  );

  const sharedProps = { allUsers, setAllUsers, comments, setComments, notifications, setNotifications, onViewProfile: setProfileView, messages, setMessages };

  return (
    <div className="app">
      <StyleTag />
      <div ref={notifRef} style={{ position: "relative" }}>
        <Nav user={user} onLogout={() => setUser(null)} notifications={notifications} onOpenNotifs={openNotifs} showNotifs={showNotifs} onCloseNotifs={() => setShowNotifs(false)} />
      </div>
      {user.role === "coach" ? (
        <CoachView user={user} workouts={workouts} scores={scores} setWorkouts={setWorkouts} setScores={setScores} {...sharedProps} />
      ) : (
        <AthleteView user={user} workouts={workouts} scores={scores} setScores={setScores} {...sharedProps} />
      )}
    </div>
  );
}
